background.code:
// --- CONFIGURAZIONE ---
// Costruiamo il vettore posizione usando u e v (già forniti dal sistema)
// Moltiplichiamo per 8.0 per fare "zoom out" e vedere più dettagli
vec2 p = vec2(u, v) * 8.0;

// --- DISTORSIONE (Domain Warping) ---
// Calcoliamo un valore di rumore base
float n1 = sys_noise(p);

// Usiamo il rumore per spostare le coordinate del passaggio successivo
// Questo crea l'effetto fluido/liquido
vec2 shift = vec2(n1, sys_noise(p + vec2(5.0, 5.0))); 

// --- PATTERN FINALE ---
// Calcoliamo il rumore finale sulle coordinate distorte
float pattern = sys_noise(p + shift * 2.0);

// --- CONTRASTO ---
// Rendiamo i bordi più netti (taglia i grigi intermedi)
pattern = smoothstep(0.3, 0.7, pattern);

// --- COLORE ---
// Usa i colori che hai scelto nel pannello (Color 1 e Color 2)
return mix(u_col1, u_col2, pattern);

texture.code:
// --- PARAMETRI ---
// Imposta nel dock: Rosso (c1) e Bianco (c2) per l'effetto classico
vec3 c1 = u_col1;
vec3 c2 = u_col2;

// --- CONFIGURAZIONE SPIRALE ---
// Coils: Quante strisce vedi in una sezione trasversale del tubo
float coils = 6.0;

// Twists: Quanti giri completi fa la spirale lungo tutto il toro
// Deve essere un numero intero per evitare che la texture si tagli alla giunzione
float twists = 40.0;

// --- CALCOLO ---
// La magia è sommare U e V moltiplicati.
// (u * twists) spinge la texture lungo il percorso
// (v * coils) avvolge la texture attorno al tubo
// Sommando i due si ottiene una linea diagonale (elica/spirale)
float pos = (u * twists) + (v * coils);

// --- CREAZIONE STRISCE NETTE ---
// fract(pos) crea un dente di sega da 0.0 a 1.0 ripetuto
// step(0.5, ...) taglia di netto il valore: sotto 0.5 è 0, sopra è 1.
float stripe = step(0.5, fract(pos));

// Restituisce il colore (senza sfumature)
return mix(c1, c2, stripe);
